
'use client';

import React, { useState, useEffect, useRef, Suspense, useCallback } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useToast } from '@/hooks/use-toast';
import ImageUploader from '@/components/app/image-uploader';
import { createKissVideoAction, upgradeUserToProAction } from '@/app/actions';
import type { CreateKissVideoActionInput } from '@/app/actions';
import { Button } from '@/components/ui/button';
import { Loader2, Wand2, ArrowLeft, Eye, Download } from 'lucide-react';
import { Progress } from "@/components/ui/progress";
import Image from 'next/image';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import SubscriptionDialog from '@/components/app/subscription-dialog';
import { useAuth } from '@/contexts/auth-context';

type AppState = 'form' | 'loading' | 'result' | 'teaser';
type LoadingReason = 'generating' | 'teaser' | 'upgrading';

function PageContent() {
  const { user, userProfile, loading: authLoading, refreshUserProfile } = useAuth();
  const router = useRouter();
  const searchParams = useSearchParams();
  const [appState, setAppState] = useState<AppState>('form');
  const [loadingReason, setLoadingReason] = useState<LoadingReason>('generating');
  const [image1, setImage1] = useState<string | null>(null);
  const [image2, setImage2] = useState<string | null>(null);
  const [sourceImageUrl, setSourceImageUrl] = useState<string | null>(null);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [canGenerate, setCanGenerate] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isSubDialogOpen, setIsSubDialogOpen] = useState(false);
  const { toast } = useToast();
  const teaserTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const progressIntervalRef = useRef<NodeJS.Timeout | null>(null);
  const isUpgradingRef = useRef(false);
  
  const saveStateToSession = () => {
    try {
        const stateToSave = { image1, image2 };
        sessionStorage.setItem('preLoginState', JSON.stringify(stateToSave));
    } catch (e) {
        console.error("Failed to save state to session storage", e);
    }
  };

  const restoreStateFromSession = useCallback(() => {
    try {
      const savedState = sessionStorage.getItem('preLoginState');
      if (savedState) {
        const { image1: savedImage1, image2: savedImage2 } = JSON.parse(savedState);
        if (savedImage1) setImage1(savedImage1);
        if (savedImage2) setImage2(savedImage2);
        return { restoredImage1: savedImage1, restoredImage2: savedImage2 };
      }
    } catch (e) {
      console.error("Failed to restore state from session storage", e);
    }
    return null;
  }, []);


  const startRealGeneration = useCallback(async (isOptimistic: boolean = false) => {
    const restoredData = restoreStateFromSession();
    
    const currentImage1 = restoredData?.restoredImage1 || image1;
    const currentImage2 = restoredData?.restoredImage2 || image2;
    
    if (!currentImage1 || !currentImage2 || !user) {
        toast({ variant: 'destructive', title: 'Error', description: 'Missing required data to start generation.' });
        setAppState('form');
        return;
    }
    
    setLoadingReason(isOptimistic ? 'upgrading' : 'generating');
    setAppState('loading');
    setProgress(0);

    const duration = 40000;
    const updateInterval = 100;
    const totalSteps = duration / updateInterval;

    if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    progressIntervalRef.current = setInterval(() => {
        setProgress(prev => Math.min(prev + (100 / totalSteps), 95));
    }, updateInterval);

    try {
        const actionInput: CreateKissVideoActionInput = {
            userId: user.uid,
            image1DataUri: currentImage1,
            image2DataUri: currentImage2,
            isOptimistic, // Pass the optimistic flag to the server action
        };

        const result = await createKissVideoAction(actionInput);

        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setProgress(100);

        if (result.error) {
            setAppState('form');
            toast({
              variant: 'destructive',
              title: 'Video Generation Failed',
              description: result.error,
              duration: 9000,
            });
        } else if (result.videoDataUri && result.sourceImageDataUri) {
            setVideoUrl(result.videoDataUri);
            setSourceImageUrl(result.sourceImageDataUri);
            setAppState('result');
            await refreshUserProfile(); // Refresh profile after a successful generation
        }
    } catch(e) {
        console.error("Error during generation action:", e);
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setAppState('form');
        const message = e instanceof Error ? e.message : 'An unknown error occurred.';
        toast({ variant: 'destructive', title: 'An Error Occurred', description: `Could not start video generation: ${message}`, duration: 9000 });
    }
  }, [user, image1, image2, restoreStateFromSession, toast, refreshUserProfile]);
  

  useEffect(() => {
    const handlePaymentSuccess = async () => {
        if (!user || isUpgradingRef.current) return;
        isUpgradingRef.current = true;

        setLoadingReason('upgrading');
        setAppState('loading');
        setProgress(0);

        // Step 1: Upgrade the user account and wait for it to complete.
        const upgradeResult = await upgradeUserToProAction(user.uid);
        
        if (!upgradeResult.success) {
            toast({
                variant: 'destructive',
                title: 'Account Upgrade Failed',
                description: upgradeResult.error || 'Could not upgrade your account. Please contact support.',
                duration: 9000
            });
            setAppState('form');
            router.replace('/', { scroll: false }); // Clean URL
            return;
        }

        // Step 2: Refresh the client-side user profile to reflect the "Pro" status.
        await refreshUserProfile();
        
        // Step 3: Now that the account is confirmed as Pro, start the video generation.
        restoreStateFromSession();
        startRealGeneration(true); // isOptimistic is true, but at this point it's just for the loading message

        router.replace('/', { scroll: false }); // Clean URL
    };

    const paidParam = searchParams.get('paid');
    const startTeaserParam = searchParams.get('start_teaser');

    if (paidParam === 'true' && user) {
        handlePaymentSuccess();
    } else if (startTeaserParam === 'true' && user) {
        restoreStateFromSession();
        handleTeaserFlow();
        router.replace('/', { scroll: false });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, searchParams, router]);


  useEffect(() => {
    const isReady = image1 && image2;
    setCanGenerate(!!isReady);
  }, [image1, image2]);

  useEffect(() => {
    return () => {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
      if (teaserTimeoutRef.current) clearTimeout(teaserTimeoutRef.current);
    };
  }, []);

  const handleTeaserFlow = () => {
    setAppState('loading');
    setLoadingReason('teaser');
    setProgress(0);
    if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    if (teaserTimeoutRef.current) clearTimeout(teaserTimeoutRef.current);

    const teaserDuration = 8000;
    progressIntervalRef.current = setInterval(() => {
        setProgress(prev => Math.min(prev + 100 / (teaserDuration / 100), 100));
    }, 100);

    teaserTimeoutRef.current = setTimeout(() => {
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setProgress(100);
        
        const teaserSourceImage = image2 || image1;
        setSourceImageUrl(teaserSourceImage);

        setAppState('teaser');
    }, teaserDuration);
  };


  const handleGenerate = () => {
    if (!canGenerate) {
      toast({ variant: 'destructive', title: 'Missing Images', description: 'Please upload all required images.' });
      return;
    }
    
    saveStateToSession();

    if (!user) {
        router.push('/login?tab=signup&start_teaser=true');
        return;
    }

    if (userProfile) {
        const isPaidUser = userProfile.isSubscribed || userProfile.credits > 0;
        if (isPaidUser) {
            startRealGeneration();
        } else {
            handleTeaserFlow();
        }
    } else {
        handleTeaserFlow();
    }
  };


  const handleSeeVideo = () => {
     saveStateToSession();
     if (!user) {
        router.push('/login?tab=signup&start_teaser=true');
        return;
     }
     
     if (userProfile) {
        const isPaidUser = userProfile.isSubscribed || userProfile.credits > 0;
        if (isPaidUser) {
            startRealGeneration();
        } else {
            setIsSubDialogOpen(true);
        }
     } else {
        setIsSubDialogOpen(true);
     }
  };

  const handleDownload = () => {
    if (!videoUrl) return;
    const link = document.createElement('a');
    link.href = videoUrl;
    link.download = 'eternal-kiss.mp4';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleReset = () => {
    setAppState('form');
    setImage1(null);
    setImage2(null);
    setSourceImageUrl(null);
    setVideoUrl(null);
    setProgress(0);
    setLoadingReason('generating');
    sessionStorage.removeItem('preLoginState');
    isUpgradingRef.current = false;
    router.replace('/', { scroll: false });
  };

  if (authLoading && !user) {
     return (
        <div className="flex items-center justify-center h-full">
            <Loader2 className="h-12 w-12 animate-spin text-primary" />
        </div>
    );
  }

  const getButtonText = () => {
    if (appState === 'loading') return 'Generating...';
    return 'Generate Kiss';
  };

  const renderLoadingState = () => {
      let title = 'Creating your teaser...';
      let description = "This will just take a moment. Please don't close this page.";

      if(loadingReason === 'generating') {
          title = 'Creating your video...';
          description = "This can take up to a minute. Please don't close this page.";
      }
      
      if(loadingReason === 'upgrading') {
          title = 'Finalizing your Pro account & starting...';
          description = "Thank you for your purchase! We are starting your video generation. This can take up to a minute.";
      }

      return (
        <div className="flex flex-col items-center justify-center gap-6 text-center w-full max-w-md">
            <Loader2 className="h-12 w-12 animate-spin text-pink-500" />
            <div className="w-full space-y-2">
                <h2 className="text-2xl font-semibold font-headline">
                  {title}
                </h2>
                <p className="text-muted-foreground">
                    {description}
                </p>
                <div className="flex items-center gap-2">
                  <Progress value={progress} className="w-full" showShimmer={true} />
                  <span className="text-sm font-medium text-muted-foreground w-10 text-right">{Math.round(progress)}%</span>
                </div>
            </div>
        </div>
      );
  };

  const renderResultState = () => (
     <Card className="w-full overflow-hidden shadow-2xl bg-gradient-to-br from-purple-50 via-pink-50 to-red-50">
        <CardHeader className="text-center p-6">
            <CardTitle className="text-3xl font-headline bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
              Your Kiss is Ready!
            </CardTitle>
            <CardDescription className="text-muted-foreground">
              Here is your moment of magic.
            </CardDescription>
        </CardHeader>

        <CardContent className="p-4 pt-0">
          <div className="relative rounded-lg overflow-hidden border-4 border-white shadow-lg aspect-video">
              {videoUrl ? (
                  <video src={videoUrl} controls autoPlay loop className="w-full h-full object-cover" />
              ) : null}
          </div>
      </CardContent>

      <CardFooter className="p-4 pt-0 flex flex-col sm:flex-row gap-3">
        <Button variant="outline" onClick={handleReset} className="w-full">
          <ArrowLeft className="mr-2 h-4 w-4" />
          Create Another
        </Button>
        {videoUrl && (
          <Button onClick={handleDownload} className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white">
              <Download className="mr-2 h-4 w-4" />
              Download Video
          </Button>
        )}
      </CardFooter>
    </Card>
  );

  const renderTeaserState = () => (
    <Card className="w-full overflow-hidden shadow-2xl bg-gradient-to-br from-purple-50 via-pink-50 to-red-50">
      <CardHeader className="text-center p-6">
          <CardTitle className="text-3xl font-headline bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
            Your Kiss is Ready!
          </CardTitle>
          <CardDescription className="text-muted-foreground">
            Unlock your video to see the magic moment.
          </CardDescription>
      </CardHeader>
      <CardContent className="p-4 pt-0">
        <div className="relative rounded-lg overflow-hidden border-4 border-white shadow-lg aspect-video">
            <Image
                src={sourceImageUrl || 'https://placehold.co/1280x720.png'}
                alt="Blurred preview of the generated video"
                width={1280}
                height={720}
                className="w-full h-full object-cover filter blur-lg scale-110"
            />
            <div className="absolute inset-0 bg-black/30 flex items-center justify-center">
                <Button onClick={handleSeeVideo} size="lg" className="bg-white/20 hover:bg-white/30 text-white backdrop-blur-sm">
                    <Eye className="mr-2 h-5 w-5" />
                    See the Video
                </Button>
            </div>
        </div>
      </CardContent>
      <CardFooter className="p-4 pt-0">
         <Button variant="outline" onClick={handleReset} className="w-full">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Start Over
          </Button>
      </CardFooter>
    </Card>
  );

  return (
    <>
      <SubscriptionDialog
        open={isSubDialogOpen}
        onOpenChange={setIsSubDialogOpen}
       />
     
      <main className="flex-grow flex items-center justify-center p-4">
          <div className="w-full max-w-xl mx-auto">
            {appState === 'form' && (
              <div className="space-y-6">
                <div className="text-center">
                  <h2 className="text-5xl font-extrabold tracking-tighter bg-gradient-to-r from-pink-500 to-purple-600 bg-clip-text text-transparent">
                    Kiss Your Crush with AI
                  </h2>
                </div>
                <ImageUploader
                  image1={image1}
                  setImage1={setImage1}
                  image2={image2}
                  setImage2={setImage2}
                />
                <div className="space-y-3">
                  <Button
                    onClick={handleGenerate}
                    disabled={!canGenerate || (appState === 'loading')}
                    size="lg"
                    className="w-full bg-gradient-to-r from-pink-500 to-purple-600 hover:from-pink-600 hover:to-purple-700 text-white disabled:opacity-75"
                  >
                     {appState === 'loading' ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <Wand2 className="mr-2 h-5 w-5" />}
                    {getButtonText()}
                  </Button>
                </div>
              </div>
            )}

            {appState === 'loading' && renderLoadingState()}
            {appState === 'result' && renderResultState()}
            {appState === 'teaser' && renderTeaserState()}

          </div>
        </main>
    </>
  );
}

export default function Home() {
    return (
        <Suspense fallback={
            <div className="flex items-center justify-center h-screen">
                <Loader2 className="h-12 w-12 animate-spin text-primary" />
            </div>
        }>
            <PageContent />
        </Suspense>
    );
}
