
'use server';

import { generateKissVideo, type GenerateKissVideoInput as FlowInput } from '@/ai/flows/generate-kiss-video';
import { decrementUserCreditsAdmin, checkUserSubscriptionAdmin, grantProAccessAdmin } from '@/lib/firebase/firebase-admin';

// This is the input type for the client-facing action.
// It includes the userId which is needed for business logic.
export type CreateKissVideoActionInput = FlowInput & {
  userId: string;
  isOptimistic?: boolean; // If true, skip credit check and assume user has paid.
};


export async function upgradeUserToProAction(userId: string): Promise<{ success: boolean; error?: string }> {
    if (!userId) {
        return { success: false, error: 'User ID is required.' };
    }
    try {
        await grantProAccessAdmin(userId);
        return { success: true };
    } catch (e: any) {
        console.error(`Failed to upgrade user ${userId} to pro:`, e);
        return { success: false, error: e.message || 'An unknown error occurred during upgrade.' };
    }
}


export async function createKissVideoAction(
  input: CreateKissVideoActionInput
): Promise<{ videoDataUri?: string; sourceImageDataUri?: string; error?: string }> {

  if (!process.env.GEMINI_API_KEY) {
    return { error: 'The Gemini API key is not configured on the server. Please contact support.' };
  }
  
  try {
    // Only check for credits if this is not an optimistic call right after payment.
    // The webhook will handle the account update, we just need to let the user generate.
    if (!input.isOptimistic) {
        const userProfile = await checkUserSubscriptionAdmin(input.userId);
        if (!userProfile || (!userProfile.isSubscribed && userProfile.credits <= 0)) {
          return { error: 'You do not have enough credits to generate a video. Please subscribe or renew to get more.' };
        }
    }

    const flowInput: FlowInput = {
        image1DataUri: input.image1DataUri,
        image2DataUri: input.image2DataUri,
    };

    const result = await generateKissVideo(flowInput);


    if (result.error) {
        return { error: result.error };
    }

    if (!result.videoDataUri || !result.sourceImageDataUri) {
        return { error: 'The AI failed to return a video or source image. Please try again.' };
    }
    
    // Always try to decrement credits. If the call was optimistic,
    // the credits might not be there yet, but the webhook will add them soon.
    // The decrement operation will fail gracefully if credits are 0.
    // We don't decrement in optimistic calls because the upgrade action gives the full credits.
    if (!input.isOptimistic) {
      await decrementUserCreditsAdmin(input.userId);
    }


    return { videoDataUri: result.videoDataUri, sourceImageDataUri: result.sourceImageDataUri };

  } catch (e: any) {
    // Provide more user-friendly error messages based on the error stack.
    const message = e.stack || e.message || 'An unknown error occurred.';
    if (message.includes('quota')) {
        return { error: 'We are experiencing high demand and have run out of capacity. Please try again later.' };
    }
    if (message.includes('Invalid argument') || message.includes('could not process the image') || message.includes('Image fusion model did not return an image')) {
        return { error: 'The AI could not process the image(s). Please try with different, higher-quality photos (clear, well-lit faces).' };
    }
    if (message.includes('API key not valid') || message.includes('API key is invalid') || message.includes('GEMINI_API_KEY')) {
        return { error: 'The API key configured on the server is invalid. Please contact support.' };
    }
    if (message.includes('User has no credits')) {
        return { error: 'You do not have enough credits to generate a video. Please subscribe or renew to get more.' };
    }
    
    return { error: `An unexpected server error occurred. Please report this. Details: ${e.message}` };
  }
}
